#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=3e5+10,M=6e5+10;
struct SAM{int ch[26],fa,len,siz;}t[N];char s[N];
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
	inline void Init(bool q=0){memset(head,0,sizeof(head));cnt=q;}
}a;
int lst,cnt;
inline void ins(int c)
{
//	printf("char %c",c+'a');
	int p=lst,np=lst=++cnt;t[np].len=t[p].len+1;
	for(;p&&!t[p].ch[c];p=t[p].fa)t[p].ch[c]=np;
	if(!p){t[np].fa=1;return;}int v=t[p].ch[c];
	if(t[v].len==t[p].len+1){t[np].fa=v;return;}
	int nv=++cnt;t[nv]=t[v];t[nv].len=t[p].len+1;
	for(;p&&t[p].ch[c]==v;p=t[p].fa)t[p].ch[c]=nv;
	t[np].fa=t[v].fa=nv; return;
}
inline void dfs(int u=1){grep(a,u,i){int v=a.des[i];dfs(v);t[u].siz+=t[v].siz;}}
inline void Solve()
{
	memset(t,0,sizeof(t));lst=1;cnt=1;scanf("%s",s);
	int len=strlen(s);rep(0,len-1,i)ins(s[i]-'a');
	a.Init();rep(2,cnt,i)a.ins(t[i].fa,i);
//	rep(1,cnt,i)grep(a,i,j)printf("%d' %d'\n",i,a.des[j]);
	int tmp=1;rep(0,len-1,i)tmp=t[tmp].ch[s[i]-'a'],t[tmp].siz=1;
	dfs();long long ans=0;
	rep(2,cnt,i)ans+=1ll*t[i].siz*t[i].siz*(t[i].len-t[t[i].fa].len);
	printf("%lld\n",ans);return;
}
int main(){int T=read();while(T--)Solve();return 0;}
